--- 保卫战, 地图对象 数据

---@class LDefenceWarObjData
local LDefenceWarObjData = LxClass("LDefenceWarObjData", nil)

local Vector3 = Vector3

local AttrEnum = {
    walkSpeed = "walkSpeed",
    hp        = "hp",
    def       = "def",
}

function LDefenceWarObjData:LDefenceWarObjData(obj)
    self._obj = obj
end

-- 销毁
function LDefenceWarObjData:Destroy()
    table.removeall(self)
end

-- 初始化
function LDefenceWarObjData:Init(monsterRefId, groupRefId, iniPos)
    self._monsterRefId = monsterRefId
    self._groupRefId = groupRefId
    self._iniPos = iniPos

    self._groupRef = gModelDefenceWar:GetMonsterGroupRef(groupRefId)
    self._monsterRef = gModelDefenceWar:GetMonsterRef(monsterRefId)

    self:InitAttr()
end

-- 初始化属性
function LDefenceWarObjData:InitAttr()
    local groupRef = self:GetGroupRef()
    local monsterRef = self:GetMonsterRef()

    -- 移动速度
    self._moveSpeed = monsterRef.walkSpeed

    -- 生命值
    self._hp = monsterRef.hp * (groupRef.hp * 0.01)

    -- 最大生命值
    self._hpMax = self._hp

    -- 攻击力
    self._atk = monsterRef.atk

    -- 防御力
    self._def = monsterRef.def

    -- 技能cd
    self._skilllCd = monsterRef.skillCd

    -- 怪物产生的经验
    self._exp = monsterRef.exp

    -- buff列表
    self._buffList = {}
end

-- 获取怪物配置
function LDefenceWarObjData:GetMonsterRef()
    return self._monsterRef
end

-- 获取怪物组配置
function LDefenceWarObjData:GetGroupRef()
    return self._groupRef
end

-- true:需要显示血条
function LDefenceWarObjData:NeedShowBlood()
    return self:GetMonsterRef().displayHp == 1
end

--  获取初始缩放
function LDefenceWarObjData:GetInitScale()
    local monsterRef = self:GetMonsterRef()
    return monsterRef.scale
end

-- 获取模形预制体名称
function LDefenceWarObjData:GetSpinePrefabName()
    local monsterRef = self:GetMonsterRef()
    local heroRefId = monsterRef.monsterShow
    local heroEffectRef = gModelHero:GetHeroEffectRef(heroRefId)
    return heroEffectRef.prefabName
end

-- 获取移动速度
function LDefenceWarObjData:GetMoveSpeed()
    local value = self:GetBuffAttr(AttrEnum.walkSpeed, self._moveSpeed)
    value = self._moveSpeed + value
    if value < 0 then
        value = 0
    end
    return value
end

-- 获取初始位置
function LDefenceWarObjData:GetInitPos()
    if self._iniPos then
        return self._iniPos
    end

    local x = math.random(-260, 260)
    local y = gModelDefenceWar:GetMonsterInitHeight()
    return Vector3(x * 0.01, y, 0)
end

-- UpDate
function LDefenceWarObjData:Update(dt)
end

-- 获取攻击
function LDefenceWarObjData:GetAtk()
    local value = self:GetBuffAttr(AttrEnum.atk, self._atk)
    value = self._atk - value
    if value < 0 then
        value = 0
    end
    return value
end

-- 获取防御
function LDefenceWarObjData:GetDef()
    local value = self:GetBuffAttr(AttrEnum.def, self._def)
    value = self._def - value
    if value < 0 then
        value = 0
    end
    return value
end

-- 获取当前血量
function LDefenceWarObjData:GetHp()
    local value = self:GetBuffAttr(AttrEnum.hp, self._hpMax)
    value = self._hp - value
    if value < 0 then
        value = 0
    end
    return value
end

-- 设置当前血量
function LDefenceWarObjData:SetHp(hp)
    self._hp = hp
end

-- 获取最大血量
function LDefenceWarObjData:GetHpMax()
    return self._hpMax
end

-- 获取经验
function LDefenceWarObjData:GetExp()
    return self._exp
end

-- 添加buff
function LDefenceWarObjData:AddBuff(data)
    for _, v in ipairs(self._buffList) do
        if v.heroId == data.heroId and v.skillId == data.skillId then
            v.attrValue = data.attrValue
            return
        end
    end

    local buff = {
        heroId    = data.heroId,
        skillId   = data.skillId,
        skillLev  = data.skillLev,
        attrName  = data.attrName,
        attrType  = data.attrType,
        attrValue = data.attrValue,
    }
    table.insert(self._buffList, buff)
end

-- 移除buff
function LDefenceWarObjData:RemoveBuff(heroId, skillId)
    for k, v in ipairs(self._buffList) do
        if v.heroId == heroId and v.skillId == skillId then
            table.remove(self._buffList, k)
            return
        end
    end
end

-- 获取buff属性
function LDefenceWarObjData:GetBuffAttr(attrName, baseVal)
    local val = 0
    for _, tab in ipairs(self._buffList) do
        if tab.attrName == attrName then
            if tab.attrType == 1 then
                -- 百分比
                val = val + baseVal * tab.attrValue * 0.01
            else
                val = val + tab.attrValue
            end
        end
    end
    return val
end

-- 获取buff列表
function LDefenceWarObjData:GetBuffList()
    return self._buffList
end

return LDefenceWarObjData
